<?php require_once __DIR__ . '/app/auth.php'; require_login(); $pdo=db(); require_once __DIR__ . '/app/layout.php'; $month=$_GET['month']??current_month(); $st=$pdo->prepare('SELECT pay.*,c.name customer_name,c.customer_code FROM payments pay JOIN customers c ON c.id=pay.customer_id WHERE pay.invoice_month=? ORDER BY pay.paid_at DESC'); $st->execute([$month]); $rows=$st->fetchAll(); $total=array_sum(array_column($rows,'amount')); render_header('Laporan Pemasukan'); ?>
<div class="hero-strip report-hero"><div class="hero-card"><p class="font-black uppercase tracking-[.18em] text-white/75 text-xs mb-2">Financial report</p><h2>Rekap pemasukan yang mudah dibaca dan diaudit.</h2><p class="text-white/85">Pantau nominal, jumlah transaksi, dan detail pembayaran per bulan.</p></div><div class="quick-card"><p class="eyebrow">Periode aktif</p><h2 class="text-2xl font-black tracking-tight mb-3"><?=e($month)?></h2><div class="text-slate-500 font-bold">Total transaksi: <?=count($rows)?></div></div></div>
<div class="card"><div class="panel-title"><h2>Rekap Bulanan</h2><form><input class="rounded-xl border px-3 py-2" type="month" name="month" value="<?=e($month)?>"><button class="btn soft">Tampilkan</button></form></div><div class="cards mb-4"><div class="card metric"><small>Total Pemasukan</small><strong><?=rupiah($total)?></strong><span class="pill green"><?=e($month)?></span></div><div class="card metric"><small>Jumlah Transaksi</small><strong><?=count($rows)?></strong><span class="pill blue">Pembayaran</span></div></div><div class="table-wrap"><table><thead><tr><th>Tanggal</th><th>Pelanggan</th><th>Kode</th><th>Nominal</th><th>Metode</th><th>Penerima</th></tr></thead><tbody><?php foreach($rows as $r):?><tr><td><?=e($r['paid_at'])?></td><td><?=e($r['customer_code'].' - '.$r['customer_name'])?></td><td><?=e($r['payment_code'])?></td><td><b><?=rupiah($r['amount'])?></b></td><td><?=e($r['method'])?></td><td><?=e($r['received_by'])?></td></tr><?php endforeach;if(!$rows):?><tr><td colspan="6">Belum ada transaksi pada bulan ini.</td></tr><?php endif;?></tbody></table></div></div><?php render_footer(); ?>
